const SUMMARIES_PART2 = {
  algorithmic_trading_and_dma: {
    summary: "Barry Johnson provides the definitive guide to electronic market microstructure and execution algorithms. The book covers how modern exchanges work, the mechanics of order matching, smart order routing, and the algorithms (TWAP, VWAP, implementation shortfall) used by institutions to execute large orders with minimal market impact. Essential reading for anyone building execution systems or trying to understand why their orders get filled the way they do.",
    keyTakeaways: ["Market microstructure determines how and at what price your orders get filled", "VWAP, TWAP, and implementation shortfall algorithms each optimize for different execution objectives", "Dark pools and hidden liquidity account for 40%+ of US equity volume", "Market impact is the biggest hidden cost of trading — it dwarfs commissions for large orders", "Understanding order book dynamics gives you an edge in timing entries and exits"],
    mindmap: { title: "Algorithmic Trading and DMA", branches: [
      { name: "Market Structure", leaves: [{ name: "Order Matching", detail: "Price-time priority determines which orders get filled first" }, { name: "Maker-Taker Model", detail: "Exchanges pay rebates for adding liquidity and charge fees for removing it" }, { name: "Fragmentation", detail: "Orders can be routed to dozens of venues — smart routing is critical" }] },
      { name: "Execution Algorithms", leaves: [{ name: "TWAP", detail: "Time-Weighted Average Price — spread orders evenly over a time window" }, { name: "VWAP", detail: "Volume-Weighted — match the market's volume profile throughout the day" }, { name: "Implementation Shortfall", detail: "Minimize the gap between decision price and actual execution price" }] },
      { name: "Market Impact", leaves: [{ name: "Temporary Impact", detail: "Price displacement that reverses after your order completes" }, { name: "Permanent Impact", detail: "Information leakage that permanently moves the price against you" }, { name: "Optimal Execution", detail: "Almgren-Chriss model balances urgency against market impact" }] },
      { name: "Dark Pools", leaves: [{ name: "Crossing Networks", detail: "Match buy and sell orders at midpoint without displaying to the market" }, { name: "Advantages", detail: "Reduced market impact and information leakage for large orders" }, { name: "Risks", detail: "Adverse selection and lower fill rates compared to lit exchanges" }] }
    ]}
  },
  advances_in_financial_machine_learning: {
    summary: "Marcos Lopez de Prado addresses the unique challenges of applying machine learning to financial data. Standard ML techniques fail in finance due to non-stationarity, low signal-to-noise ratios, and overfitting. The book introduces novel techniques: fractional differentiation to make time series stationary while preserving memory, meta-labeling to size positions using an ML model on top of a primary strategy, and proper cross-validation for financial time series.",
    keyTakeaways: ["Standard cross-validation is invalid for financial time series due to data leakage — use purged k-fold CV instead", "Fractional differentiation makes price series stationary while preserving long-range memory that full differencing destroys", "Meta-labeling uses a secondary ML model to decide the SIZE of a position, not the direction — dramatically improves Sharpe ratios", "Feature importance methods in finance must account for multicollinearity — use mean decrease impurity with caution", "Most published backtests are overfit — the probability of backtest overfitting should be calculated before trusting results"],
    mindmap: { title: "Advances in Financial Machine Learning", branches: [
      { name: "Data Structures", leaves: [{ name: "Bars (Volume/Dollar)", detail: "Sample by volume or dollar amount traded instead of fixed time intervals" }, { name: "Information-Driven Bars", detail: "Tick imbalance and volume imbalance bars capture informed trading activity" }, { name: "Labeling", detail: "Triple-barrier method labels outcomes more accurately than fixed-horizon returns" }] },
      { name: "Feature Engineering", leaves: [{ name: "Fractional Differentiation", detail: "Make series stationary while keeping memory using fractional d between 0 and 1" }, { name: "Entropy Features", detail: "Measure information content and predictability of return series" }, { name: "Structural Breaks", detail: "CUSUM tests detect regime changes in the data generating process" }] },
      { name: "ML Techniques", leaves: [{ name: "Meta-Labeling", detail: "Secondary model that sizes positions from a primary model's signals" }, { name: "Purged Cross-Validation", detail: "Remove overlapping samples between train/test sets to prevent leakage" }, { name: "Feature Importance", detail: "MDI, MDA, and SFI methods to identify genuinely predictive features" }] },
      { name: "Backtesting", leaves: [{ name: "Combinatorial Purged CV", detail: "Generate multiple train/test paths to estimate probability of overfitting" }, { name: "Walk-Forward", detail: "Rolling window approach that mimics real trading conditions" }, { name: "Deflated Sharpe Ratio", detail: "Adjust Sharpe ratio for the number of trials and selection bias" }] }
    ]}
  },
  the_concepts_and_practice_of_mathematical_finance: {
    summary: "Mark Joshi balances mathematical rigor with practical implementation. The book covers derivatives pricing from first principles through to advanced exotic options, with strong emphasis on Monte Carlo methods and their implementation. Joshi's clear explanations of measure theory, martingales, and change of numeraire make this a favorite for quant interview preparation and self-study.",
    keyTakeaways: ["Understanding change of numeraire simplifies many pricing problems dramatically", "Monte Carlo methods are the most flexible tool for pricing complex derivatives", "Variance reduction techniques (antithetic, control variates) make Monte Carlo practical", "Early exercise (American options) requires backward induction — Longstaff-Schwartz algorithm", "The Greeks can be computed via finite differences, pathwise methods, or likelihood ratio methods"],
    mindmap: { title: "Mathematical Finance", branches: [
      { name: "Foundations", leaves: [{ name: "Measure Theory", detail: "Risk-neutral measure transforms expected return to the risk-free rate" }, { name: "Martingales", detail: "Discounted asset prices are martingales under the risk-neutral measure" }, { name: "Change of Numeraire", detail: "Switch between measures to simplify pricing of different derivative types" }] },
      { name: "Pricing Methods", leaves: [{ name: "Monte Carlo", detail: "Simulate thousands of paths and average discounted payoffs" }, { name: "Trees", detail: "Binomial and trinomial trees for American options pricing" }, { name: "PDE Methods", detail: "Solve Black-Scholes PDE via finite differences on a grid" }] },
      { name: "Exotic Options", leaves: [{ name: "Barrier Options", detail: "Knock-in/knock-out features that activate or deactivate at price levels" }, { name: "Asian Options", detail: "Payoff based on average price over a period rather than terminal price" }, { name: "Lookback Options", detail: "Payoff based on the maximum or minimum price achieved during the life" }] },
      { name: "Implementation", leaves: [{ name: "Variance Reduction", detail: "Antithetic variates and control variates reduce Monte Carlo error" }, { name: "Greeks Computation", detail: "Finite difference, pathwise, and likelihood ratio approaches" }, { name: "Calibration", detail: "Fit model parameters to observed market option prices" }] }
    ]}
  },
  trading_in_the_zone: {
    summary: "Mark Douglas makes the case that trading success is overwhelmingly determined by psychology rather than by strategy or market knowledge. The book's central argument is that inconsistent trading results are not caused by insufficient market analysis but by flawed mental frameworks — specifically, a failure to genuinely accept risk and to think in probabilities. Douglas identifies the five fundamental truths that, once internalized, dissolve the emotional reactions that cause traders to deviate from their own rules. The transition from inconsistent to consistent trading requires more than intellectual understanding; it demands a fundamental rewiring of the beliefs and attitudes you bring to each trade. Douglas draws on his background as a trading coach to explain precisely why traders know what they should do but cannot do it, and provides a practical framework for developing the disciplined mindset that consistent profitability requires. This is not a book about strategies — it is a book about transforming the relationship between trader and market.",
    keyTakeaways: [
      "The market is not the source of trading losses — the trader's inability to execute their own rules without emotional interference is the root cause of poor results",
      "Genuine risk acceptance means believing before entering a trade that you could lose, and being at peace with that outcome — without this, fear distorts every subsequent decision",
      "The five fundamental truths define a probabilistic mindset: anything can happen, you do not need to know what happens next to make money, every moment in the market is unique, there is a random distribution of wins and losses for any given edge, and an edge is merely a higher probability of one outcome over another",
      "Consistency is not about predicting the market correctly — it is about executing your rules flawlessly on every single trade regardless of the previous outcome",
      "Your beliefs about money, risk, and the market are not facts — they are lenses that filter what you perceive and how you respond, and they can be consciously changed",
      "The winning mindset treats trading like a casino operator, not a gambler — the casino is not attached to any individual game because it knows the edge plays out over thousands of games",
      "Fear in trading takes four forms: fear of losing money, fear of being wrong, fear of missing out, and fear of leaving money on the table — each manifests as a specific pattern of self-destructive behavior",
      "The ego's need to be right is the single most expensive psychological trait a trader can have — it prevents cutting losses, causes averaging down, and leads to revenge trading",
      "Building consistency requires defining your edge with total precision, committing to taking every signal for a sample of 20-30 trades, evaluating results statistically rather than trade by trade",
      "Mental discipline is not about willpower — it is about holding beliefs that make disciplined behavior the path of least resistance, not a constant internal battle",
      "Common mental traps include reinterpreting market information to match a losing position, moving stops to avoid taking a loss, and skipping valid signals after a string of losses",
      "Daily mental preparation — reviewing your rules before the session, setting explicit intentions, and debriefing after the session — is as important as any technical preparation"
    ],
    mindmap: { title: "Trading in the Zone", branches: [
      { name: "The Probabilistic Mindset", leaves: [
        { name: "Think in Probabilities, Not Certainties", detail: "Each trade has an uncertain outcome — the edge is statistical, meaning it only manifests over many trades; judging any individual outcome as success or failure distorts your thinking" },
        { name: "The Casino Metaphor", detail: "Casinos do not need to know the outcome of any individual game because they know their edge plays out reliably over thousands of games — this is the exact mindset needed for trading" },
        { name: "Detach from Individual Outcomes", detail: "Attaching emotional significance to individual trade outcomes causes the very fears and hesitations that undermine execution — each trade is just one in an infinite stream of similar situations" },
        { name: "Process Over Outcome", detail: "Judge your performance on whether you executed your rules flawlessly, not on whether the trade made money — a well-executed trade that loses is a success; a rule-breaking trade that wins is a failure" },
        { name: "Random Distribution of Wins and Losses", detail: "Within a series of trades with an edge, wins and losses are randomly distributed — a string of losses does not make the next trade more likely to win, and a string of wins does not mean the edge is failing" }
      ]},
      { name: "Five Fundamental Truths", leaves: [
        { name: "Anything Can Happen", detail: "No matter how perfect the setup, any individual trade can lose — forces acting on prices include every trader in the world, most of whose intentions you cannot know" },
        { name: "You Do Not Need to Know What Happens Next", detail: "Profitability does not require predicting the future — it only requires identifying a repeating pattern where the probabilities favor a particular outcome" },
        { name: "Every Moment in the Market Is Unique", detail: "No two market situations are truly identical — past patterns provide a probabilistic basis for expectations, not a guarantee, because the specific combination of traders and information is always different" },
        { name: "There Is a Random Distribution of Wins and Losses", detail: "For any given edge, the wins and losses are randomly distributed across the sample — this makes the outcome of any single trade essentially unknowable in advance" },
        { name: "An Edge Is Nothing More Than a Higher Probability", detail: "An edge does not guarantee the next trade will win — it only means that over a large enough sample, the strategy produces more winning trades than losing ones by a meaningful margin" }
      ]},
      { name: "Psychology of Fear", leaves: [
        { name: "Fear of Losing Money", detail: "Causes traders to place stops too tight (cut winners prematurely), hesitate before entering valid signals, or avoid trading entirely after a losing streak" },
        { name: "Fear of Being Wrong", detail: "The ego cannot accept that a losing trade reflects anything other than bad luck — this leads to moving stops, averaging down, and holding losers until they become disasters" },
        { name: "Fear of Missing Out (FOMO)", detail: "Watching a missed trade run in your predicted direction triggers urgency to chase it — chasing leads to entries at terrible prices with poor risk/reward and subsequent large losses" },
        { name: "Fear of Leaving Money on the Table", detail: "Taking profits too early because you fear a reversal — this asymmetric behavior (cutting winners and letting losers run) is the opposite of what profitability requires" },
        { name: "Fear Creates Market Errors", detail: "Every fear manifests as a distortion in how you perceive market information — you will unconsciously reinterpret data to support the action (or inaction) that your fear is driving" },
        { name: "Eliminating Fear Through Genuine Acceptance", detail: "The only way to eliminate fear is to genuinely accept before entry that the trade could lose and that this outcome is acceptable — intellectual acceptance is insufficient; it must be felt" }
      ]},
      { name: "Psychology of Greed", leaves: [
        { name: "Greed Overrides Rules", detail: "When a trade is working, greed causes traders to abandon exit rules, remove profit targets, and hold longer than planned — this converts a disciplined trade into a gamble" },
        { name: "Overtrading", detail: "Greed drives taking trades outside one's defined edge, trading too frequently, or sizing up recklessly after a winning streak — all of these behaviors erode the statistical edge" },
        { name: "Greed After a Win", detail: "Consecutive wins create overconfidence and the illusion that the trader can 'feel' the market — this is one of the most dangerous states because it leads to abandoning the systematic approach that produced the wins" },
        { name: "The Euphoria Trap", detail: "A state of euphoria following a big win or winning streak makes traders feel invincible — the market reliably punishes this state by providing a loss that is disproportionately large" },
        { name: "Separating Desire from Execution", detail: "Wanting a trade to work is normal; allowing that desire to influence how you manage it is destructive — greed and hope are indistinguishable when a trade is losing, and both lead to the same bad outcome" }
      ]},
      { name: "Belief Systems", leaves: [
        { name: "Beliefs Filter Reality", detail: "You do not see the market as it is — you see it filtered through your beliefs about money, risk, and what you deserve; changing beliefs changes what you perceive and how you respond" },
        { name: "Losing Beliefs", detail: "Common destructive beliefs include 'the market is out to get me,' 'I am not smart enough to trade,' 'I need this trade to work to pay bills' — each of these creates the exact outcome it fears" },
        { name: "Installing Winning Beliefs", detail: "The five fundamental truths, internalized deeply enough to become automatic, constitute the belief system of a consistently profitable trader — they must be rehearsed until they are felt, not merely understood" },
        { name: "Childhood and Money Beliefs", detail: "Beliefs about money formed in childhood (money is scarce, I do not deserve success, rich people are dishonest) operate unconsciously in trading decisions — surfacing and challenging them is necessary for growth" },
        { name: "Belief Change Process", detail: "New beliefs are installed by consistently acting in accordance with them — taking every valid signal even when afraid, treating small losses as just a cost of doing business, and affirming the new beliefs reinforces them" }
      ]},
      { name: "Building Consistency", leaves: [
        { name: "Define Your Edge with Precision", detail: "Write down the exact criteria that constitute a valid trade signal — vague rules allow your mind to rationalize entries that are not truly valid, and vague exits allow greed and fear to override you" },
        { name: "The 20-Trade Commitment", detail: "Commit to executing your rules flawlessly on the next 20 trades regardless of outcome — this sample is large enough to evaluate your edge statistically and short enough to be manageable as a psychological exercise" },
        { name: "Execute Without Hesitation", detail: "Take every signal your defined rules generate — cherry-picking signals based on how you feel about each one destroys the statistical validity of your edge and prevents you from gathering useful data" },
        { name: "Evaluate by Process, Not by P&L", detail: "After each 20-trade sample, evaluate how consistently you followed your rules, not how much money you made — the P&L will eventually reflect the rules; inconsistent execution prevents you from knowing if the edge works" },
        { name: "Consistency Compounds", detail: "A modest edge executed with complete consistency produces better long-term results than a strong edge executed inconsistently — every rule deviation introduces a random variable that destroys the edge's statistical basis" }
      ]},
      { name: "The Edge", leaves: [
        { name: "An Edge Is Not a System", detail: "An edge is a situation where the probabilities favor a particular outcome over a large sample — a system is the framework for identifying and exploiting that edge; the system is worthless without the discipline to execute it" },
        { name: "Defining Your Edge Objectively", detail: "Can you describe your edge without using the words 'I think' or 'it feels like'? If not, you do not have a defined edge — you have an opinion, which changes with your mood and recent trades" },
        { name: "Testing Your Edge", detail: "Historical testing provides a baseline expectation for win rate, average win, and average loss — without this data, you cannot know whether a string of losses is normal variance or a broken edge" },
        { name: "Protecting Your Edge", detail: "An edge exists relative to other market participants — if your edge is widely known and adopted, it will decay as more capital competes for the same opportunity; continuous research is required to maintain edge" },
        { name: "Trusting Your Edge", detail: "After a string of losses, the mind doubts the edge and seeks to modify it — this is precisely the wrong time to change rules; modify strategy only after a sufficiently large sample shows the edge is no longer present" }
      ]},
      { name: "Accepting Risk", leaves: [
        { name: "Risk Acceptance vs Risk Tolerance", detail: "Tolerating risk means enduring it grudgingly; accepting risk means genuinely being at peace with any outcome — only true acceptance eliminates the fear that distorts trading decisions" },
        { name: "Pre-Defining Risk Before Every Trade", detail: "Know your maximum loss in dollar terms before entering any trade — when this number is pre-accepted, the trade can be managed rationally; without it, the mind reacts emotionally when the position moves against you" },
        { name: "The Loss as a Business Cost", detail: "A loss within pre-defined parameters is not a failure — it is the cost of doing business, identical to a casino paying out on a losing bet; reframing losses this way removes their emotional power" },
        { name: "Sizing for Acceptance", detail: "If a position size makes you anxious about the potential loss, it is too large — reduce size until you can observe the trade without emotional involvement; trading smaller and consistently beats trading large and emotionally" },
        { name: "The Stop Loss as a Gift to Yourself", detail: "A stop loss is not an admission of failure — it is a decision made in advance, before fear and hope distort your thinking, to protect your capital and ensure you can trade the next opportunity" }
      ]},
      { name: "Common Mental Traps", leaves: [
        { name: "Revenge Trading", detail: "After a loss, the desire to immediately get the money back overrides systematic thinking — revenge trades are typically too large, entered at poor prices, and driven by emotion rather than edge" },
        { name: "Moving Stops to Avoid Losses", detail: "Telling yourself 'I will just give it more room' when price approaches a stop is rationalization — the original stop represented your risk tolerance when thinking clearly; changing it represents fear overriding a rational decision" },
        { name: "Averaging Down into Losers", detail: "Adding to a losing position because 'it is cheaper now' is a losing strategy — it confuses a lower price with a good trade, ignores that the original thesis was wrong, and compounds risk into a broken position" },
        { name: "Skipping Valid Signals After Losses", detail: "After a losing streak, the temptation to skip trades is strong — but the trades you skip are just as likely to be winners as the ones you take, and skipping destroys the statistical validity of your edge" },
        { name: "Overanalyzing After Losses", detail: "Changing strategy rules after every losing period leads to a constantly changing, inconsistent approach — distinguish between a strategy with a valid edge in a normal drawdown and a genuinely broken strategy" }
      ]},
      { name: "Daily Mental Preparation", leaves: [
        { name: "Pre-Session Mental Review", detail: "Before each trading session, review your rules explicitly, set your intended position limits for the day, and remind yourself of the mindset you intend to maintain — this primes the mind for disciplined execution" },
        { name: "Defining Acceptable Scenarios", detail: "Before entering any trade, mentally walk through both the winning and losing outcomes — visualize yourself executing your exit plan in both scenarios to reduce emotional reaction when they occur" },
        { name: "Post-Session Debrief", detail: "Review every trade taken against your rules — not to judge the P&L but to evaluate rule execution; identify any deviations and their cause before the memory fades" },
        { name: "Physical State Management", detail: "Sleep deprivation, hunger, and physical stress degrade the prefrontal cortex's ability to override emotional responses — the same market situation will elicit different responses depending on your physical state" },
        { name: "Trading Journal as Feedback Loop", detail: "A journal that records not just trades but mental state, rule compliance, and emotional observations provides the data needed to identify and correct recurring psychological patterns" }
      ]}
    ]}
  },
  thinking__fast_and_slow: {
    summary: "Daniel Kahneman reveals the two systems that drive human thinking: System 1 (fast, intuitive, emotional) and System 2 (slow, deliberate, logical). He catalogs dozens of cognitive biases that affect financial decision-making, from loss aversion to anchoring to the availability heuristic. Understanding these biases is the first step to making better investment decisions and avoiding the psychological traps that cost traders money.",
    keyTakeaways: ["System 1 thinking (fast, intuitive) dominates most trading decisions — and it is riddled with biases", "Loss aversion means losses hurt about 2x more than equivalent gains feel good — this distorts risk-taking behavior", "Anchoring bias causes traders to fixate on arbitrary reference points like their entry price", "Overconfidence is the most damaging bias in trading — we systematically overestimate our knowledge and abilities", "You cannot eliminate biases but you can design systems and processes that reduce their impact on decisions"],
    mindmap: { title: "Thinking, Fast and Slow", branches: [
      { name: "Two Systems", leaves: [{ name: "System 1 — Fast", detail: "Automatic, intuitive, emotional — handles 95% of daily decisions" }, { name: "System 2 — Slow", detail: "Deliberate, analytical, effortful — engaged for complex problems" }, { name: "Lazy System 2", detail: "System 2 often rubber-stamps System 1 conclusions instead of checking them" }] },
      { name: "Key Biases for Traders", leaves: [{ name: "Loss Aversion", detail: "Losing $100 feels as bad as gaining $200 feels good — distorts risk decisions" }, { name: "Anchoring", detail: "First number you see influences all subsequent judgments irrationally" }, { name: "Availability Heuristic", detail: "Recent or vivid events seem more probable than they actually are" }, { name: "Overconfidence", detail: "Experts consistently overestimate accuracy of their predictions" }] },
      { name: "Prospect Theory", leaves: [{ name: "Reference Points", detail: "People evaluate outcomes relative to a reference point, not in absolute terms" }, { name: "Diminishing Sensitivity", detail: "The difference between $100 and $200 feels bigger than between $1100 and $1200" }, { name: "Certainty Effect", detail: "People overweight outcomes that are certain vs highly probable" }] },
      { name: "Defending Against Bias", leaves: [{ name: "Checklists", detail: "Systematic processes reduce the influence of intuitive errors" }, { name: "Pre-Mortem Analysis", detail: "Imagine the trade failed — what went wrong? Reveals overlooked risks" }, { name: "Algorithms Over Intuition", detail: "Simple rules consistently outperform expert judgment in many domains" }] }
    ]}
  },
  reminiscences_of_a_stock_operator: {
    summary: "This fictionalized biography of Jesse Livermore, one of the most famous speculators of the early 20th century, reads like a novel but contains timeless trading wisdom. Written in 1923, the lessons on patience, reading the tape, position sizing, and the psychology of crowds remain as relevant today as they were a century ago. Livermore made and lost multiple fortunes, and his experiences illuminate both the potential and dangers of speculation.",
    keyTakeaways: ["It is not about being right or wrong — it is about how much you make when right and how much you lose when wrong", "The market does not beat you — you beat yourself through impatience, greed, and hope", "Patience is the hardest and most important skill — sit tight when you have a winning position", "Never add to a losing position — pyramiding should only happen when a trade is already profitable", "The big money is made in the big swings — not in day-to-day fluctuations"],
    mindmap: { title: "Reminiscences of a Stock Operator", branches: [
      { name: "Market Wisdom", leaves: [{ name: "The Trend Is Everything", detail: "Do not try to catch tops and bottoms — trade with the trend" }, { name: "Sit Tight", detail: "The hardest thing is holding a winning position — most sell too early" }, { name: "Wait for Confirmation", detail: "Do not anticipate — wait for the market to tell you it is ready to move" }] },
      { name: "Risk Management", leaves: [{ name: "Cut Losses Fast", detail: "A small loss is nothing — a big loss can end your career" }, { name: "Never Average Down", detail: "Adding to losers compounds mistakes — only add to winners" }, { name: "Probe Position First", detail: "Start with a small position to test your thesis before committing fully" }] },
      { name: "Psychology", leaves: [{ name: "Hope and Fear", detail: "Traders hope when losing (should fear) and fear when winning (should hope)" }, { name: "The Crowd Is Usually Wrong", detail: "The majority is wrong at turning points — contrarian thinking wins" }, { name: "Ego Is Expensive", detail: "The need to be right costs more money than any bad analysis" }] },
      { name: "Timeless Principles", leaves: [{ name: "Markets Never Change", detail: "Technology evolves but human nature drives the same patterns century after century" }, { name: "Study the Past", detail: "History does not repeat exactly but it rhymes — learn from past market cycles" }, { name: "Specialization Wins", detail: "Master one approach rather than dabbling in many" }] }
    ]}
  },
  the_psychology_of_money: {
    summary: "Morgan Housel uses 19 short stories to explore the strange ways people think about money. The book argues that financial success has less to do with intelligence and more to do with behavior. Through compelling anecdotes and clear reasoning, Housel shows that patience, humility, and reasonable expectations matter more than spreadsheets and complex strategies.",
    keyTakeaways: ["No one is crazy with money — everyone makes decisions based on their unique experiences and worldview", "Compounding is the most powerful force in finance — but it requires patience measured in decades, not months", "Getting wealthy requires risk-taking and optimism; staying wealthy requires humility and paranoia", "The highest dividend money pays is the ability to control your time — that is true wealth", "Room for error (margin of safety) is the most important concept in financial planning"],
    mindmap: { title: "The Psychology of Money", branches: [
      { name: "Behavior Over Intelligence", leaves: [{ name: "Soft Skills Win", detail: "Patience and emotional control matter more than financial knowledge" }, { name: "Personal History Shapes Decisions", detail: "Someone who lived through the Depression thinks about money differently" }, { name: "Reasonable > Rational", detail: "A slightly suboptimal strategy you can stick with beats a perfect one you abandon" }] },
      { name: "Compounding", leaves: [{ name: "Time Is Everything", detail: "Warren Buffett made 99% of his wealth after age 50 — compounding needs decades" }, { name: "Uninterrupted Compounding", detail: "The key is not earning the highest return but avoiding catastrophic losses" }, { name: "Tail Events", detail: "A few great investments drive the vast majority of total returns" }] },
      { name: "Wealth vs Rich", leaves: [{ name: "Rich Is Visible", detail: "Big houses, nice cars — spending money to look successful" }, { name: "Wealth Is Invisible", detail: "The money you do not spend — savings, investments, options for the future" }, { name: "Freedom", detail: "The highest form of wealth is the ability to do what you want, when you want" }] },
      { name: "Planning for Reality", leaves: [{ name: "Margin of Safety", detail: "Plan for things to go wrong — the unexpected is not just possible, it is inevitable" }, { name: "Save Without a Reason", detail: "Savings without a specific goal gives you options and flexibility" }, { name: "Define Enough", detail: "Knowing when you have enough prevents the risk of losing what you have for what you do not need" }] }
    ]}
  },
  fooled_by_randomness: {
    summary: "Nassim Taleb explores how humans consistently mistake luck for skill, especially in financial markets. Through stories of lucky traders who mistakenly believe they are geniuses, Taleb demonstrates that randomness plays a far larger role in outcomes than we acknowledge. The book introduces survivorship bias, narrative fallacy, and the problem of induction applied to trading and investing.",
    keyTakeaways: ["Most successful track records in finance contain far more luck than skill — but we cannot tell the difference", "Survivorship bias means we only see the winners — the silent graveyard of failed traders is invisible", "Humans are wired to create narratives that explain random events — this narrative fallacy distorts our understanding", "A strategy that worked for 10 years can fail catastrophically due to a regime change — past performance is not proof of skill", "Mild success through robustness is better than spectacular success through fragility"],
    mindmap: { title: "Fooled by Randomness", branches: [
      { name: "Luck vs Skill", leaves: [{ name: "Alternative Histories", detail: "Your actual outcome is one of many possible paths — you might have been unlucky in a parallel universe" }, { name: "Survivorship Bias", detail: "We study winners and ignore the equal number of losers who did the same things" }, { name: "Sample Size Problem", detail: "A few years of track record tells us almost nothing about true skill" }] },
      { name: "Narrative Fallacy", leaves: [{ name: "Pattern Matching", detail: "Humans create stories to explain random events and then believe those stories" }, { name: "Hindsight Bias", detail: "Past events seem predictable in retrospect even though they were not" }, { name: "Attribution Error", detail: "We attribute success to skill and failure to bad luck — for ourselves" }] },
      { name: "Asymmetric Outcomes", leaves: [{ name: "Black Swan Risk", detail: "Rare events have outsized impact and are systematically underestimated" }, { name: "Fragility", detail: "Strategies that look great in normal times can blow up catastrophically" }, { name: "Robustness Over Optimization", detail: "Build strategies that survive bad scenarios rather than maximizing good ones" }] },
      { name: "Practical Lessons", leaves: [{ name: "Do Not Compare", detail: "Comparing your returns to others is meaningless without knowing their risk" }, { name: "Expect Randomness", detail: "Accept that much of what happens in markets is unexplainable noise" }, { name: "Protect Against Ruin", detail: "The only thing that matters is staying in the game — avoid total loss" }] }
    ]}
  },
  the_black_swan: {
    summary: "Taleb introduces the concept of Black Swans — rare, unpredictable, high-impact events that dominate history, markets, and human affairs. He argues that our models, predictions, and risk management systems are designed for a normal world but we live in an extreme one. The 2008 financial crisis, which happened shortly after publication, proved his thesis dramatically.",
    keyTakeaways: ["Black Swans are rare, unpredictable, carry massive impact, and we rationalize them in hindsight", "The normal distribution dramatically underestimates the probability and impact of extreme events", "Forecasters are consistently terrible at predicting the future but remain confident in their predictions", "Build your portfolio to be antifragile — benefit from uncertainty rather than being destroyed by it", "The barbell strategy: put 85-90% in ultra-safe assets and 10-15% in ultra-speculative bets"],
    mindmap: { title: "The Black Swan", branches: [
      { name: "What Is a Black Swan?", leaves: [{ name: "Rarity", detail: "Outside the realm of regular expectations — no past data predicts it" }, { name: "Extreme Impact", detail: "A single event can wipe out decades of accumulated gains" }, { name: "Retrospective Predictability", detail: "After it happens, everyone explains why it was obvious" }] },
      { name: "Mediocristan vs Extremistan", leaves: [{ name: "Mediocristan", detail: "Height, weight — bell curves work, no single observation matters much" }, { name: "Extremistan", detail: "Wealth, markets, book sales — one observation can dominate all others" }, { name: "Power Laws", detail: "In Extremistan, outcomes follow power laws, not bell curves" }] },
      { name: "Why We Fail to Predict", leaves: [{ name: "Narrative Fallacy", detail: "We create explanatory stories that make randomness seem predictable" }, { name: "Tunneling", detail: "We focus on specific scenarios instead of the full space of possibilities" }, { name: "Expert Problem", detail: "In complex domains, experts are no better than chance at prediction" }] },
      { name: "The Barbell Strategy", leaves: [{ name: "Ultra-Safe + Ultra-Speculative", detail: "85-90% in treasuries, 10-15% in highly asymmetric bets" }, { name: "Avoid the Middle", detail: "Medium-risk investments give you the worst of both worlds" }, { name: "Positive Black Swans", detail: "Position yourself to benefit from unexpected positive events" }] }
    ]}
  },
  against_the_gods: {
    summary: "Peter Bernstein traces the intellectual history of risk management from ancient gamblers to modern financial theory. He shows how the mastery of risk transformed civilization — from Pascal and Fermat's probability theory through to Markowitz's portfolio theory and the Black-Scholes model. The book demonstrates that our current understanding of risk is the product of centuries of mathematical innovation.",
    keyTakeaways: ["Risk management is the central story of human progress — every advance in probability theory changed how society functions", "The distinction between risk (quantifiable) and uncertainty (unquantifiable) is fundamental to sound decision-making", "Diversification is the only free lunch in investing — it reduces risk without reducing expected return", "Even sophisticated risk models fail during extreme events — humility about our models is essential", "Regression to the mean is one of the most powerful and underappreciated statistical concepts in finance"],
    mindmap: { title: "Against the Gods", branches: [
      { name: "History of Risk", leaves: [{ name: "Probability Theory", detail: "Pascal and Fermat's correspondence laid the mathematical foundation" }, { name: "Normal Distribution", detail: "Gauss and Laplace showed natural phenomena cluster around averages" }, { name: "Law of Large Numbers", detail: "Bernoulli proved that outcomes converge to expected values over many trials" }] },
      { name: "Modern Portfolio Theory", leaves: [{ name: "Markowitz", detail: "Diversification reduces risk without sacrificing return — revolutionary insight" }, { name: "CAPM", detail: "Sharpe showed that only systematic risk is rewarded — diversifiable risk is free to eliminate" }, { name: "Efficient Markets", detail: "Fama argued prices reflect all available information — hard to beat consistently" }] },
      { name: "Derivatives Revolution", leaves: [{ name: "Black-Scholes", detail: "A formula for pricing options that launched an entire industry" }, { name: "Risk Transfer", detail: "Derivatives allow risks to be transferred to those best able to bear them" }, { name: "Model Failures", detail: "LTCM collapse showed that even brilliant models can be catastrophically wrong" }] },
      { name: "Lessons", leaves: [{ name: "Humility", detail: "Our models are approximations — extreme events will always surprise us" }, { name: "Mean Reversion", detail: "Extreme performance tends to revert toward the average over time" }, { name: "Risk vs Uncertainty", detail: "We can manage risk but we cannot manage true uncertainty" }] }
    ]}
  },
  positional_option_trading: {
    summary: "Euan Sinclair focuses on the practical side of managing options portfolios over time. Unlike books that teach individual strategies, this one teaches how to manage a book of positions: when to hedge, when to roll, how to size positions across a portfolio, and how to think about risk at the portfolio level rather than the individual trade level.",
    keyTakeaways: ["Portfolio-level risk management is fundamentally different from managing individual trades", "Greeks must be managed at the portfolio level — individual position Greeks can be misleading in aggregate", "Rolling options is a risk management decision, not a way to avoid losses", "Correlation between positions is the hidden risk — seemingly diversified options portfolios can be heavily correlated", "The Kelly criterion adapted for options accounts for the uncertainty in your edge estimate"],
    mindmap: { title: "Positional Option Trading", branches: [
      { name: "Portfolio Greeks", leaves: [{ name: "Net Delta", detail: "Total directional exposure across all positions must be monitored" }, { name: "Portfolio Gamma", detail: "Aggregate gamma determines how fast your delta changes in a move" }, { name: "Theta vs Gamma", detail: "Daily theta income should compensate for gamma risk — the fundamental tradeoff" }] },
      { name: "Position Management", leaves: [{ name: "When to Hedge", detail: "Hedge when risk exceeds tolerance, not on a fixed schedule" }, { name: "Rolling", detail: "Extend, adjust strike, or close and reopen — each has different risk implications" }, { name: "Closing Losers", detail: "Cut positions that have moved against you rather than hoping for recovery" }] },
      { name: "Sizing", leaves: [{ name: "Kelly for Options", detail: "Fractional Kelly accounts for edge uncertainty in options strategies" }, { name: "Correlation Risk", detail: "Seemingly independent positions may have hidden correlation to market factors" }, { name: "Max Position Limits", detail: "No single position should threaten portfolio survival if it goes to zero" }] },
      { name: "Practical Framework", leaves: [{ name: "Daily Review", detail: "Check portfolio Greeks, P&L attribution, and upcoming events every morning" }, { name: "Scenario Analysis", detail: "Test portfolio against crash, rally, and volatility spike scenarios" }, { name: "Record Keeping", detail: "Log every adjustment decision and review monthly for pattern improvement" }] }
    ]}
  },
  the_intelligent_investor: {
    summary: "Benjamin Graham's masterpiece, first published in 1949, establishes the philosophical and analytical foundation of value investing and remains the most influential investing book ever written. Graham introduces the concept of Mr. Market — a fictional business partner who offers to buy or sell shares every day at prices dictated by his emotional state — and argues that the intelligent investor takes advantage of Mr. Market's irrationality rather than being guided by it. The margin of safety principle — buying securities only when they trade significantly below their conservatively estimated intrinsic value — is Graham's central contribution, providing a buffer against analytical errors and unforeseen adversity. Graham draws a sharp distinction between investing (systematic analysis, safety of principal, adequate return) and speculation (everything else), arguing that most of what passes for investing in the financial press is actually speculation. The book distinguishes between the defensive investor (who wants a satisfactory result with minimal effort) and the enterprising investor (who is willing to commit serious time and effort to outperform the market), providing a specific framework for each. Warren Buffett, Graham's most famous student, calls it the best investing book ever written, and the core principles have proven durable across eight decades of financial market history.",
    keyTakeaways: [
      "Mr. Market is your servant, not your guide — his daily mood swings between euphoria and despair create opportunities for the disciplined investor to buy cheap and sell dear",
      "Margin of safety is the most important three words in investing — buying significantly below intrinsic value protects against analytical errors, business deterioration, and unforeseen market events",
      "The difference between investing and speculation is not a matter of degree but of kind: investing requires thorough analysis, safety of principal, and an adequate return; anything else is speculation",
      "Defensive investors should hold a diversified portfolio of large, conservatively financed, dividend-paying companies with long records of stable earnings, or simply buy index funds",
      "Enterprising investors can outperform by seeking bargain issues (stocks below net current asset value), special situations, or growth stocks bought at a reasonable price",
      "Stock selection for the defensive investor requires: adequate size, strong financial position, 20 years of continuous dividends, 10 years of positive earnings, reasonable P/E, and reasonable price-to-book",
      "Market fluctuations are not risks to be feared but opportunities to be exploited — the intelligent investor uses price declines to buy quality companies at attractive prices",
      "The market in the short run is a voting machine (popularity contest) but in the long run is a weighing machine (fundamental value is recognized) — this gap creates opportunity",
      "Inflation is the investor's hidden enemy — a portfolio that does not generate returns above the inflation rate is losing real wealth even if it shows nominal gains",
      "The investor's chief problem, and worst enemy, is likely to be themselves — overreaction to market fluctuations, attention to tips, and emotional decision-making destroy returns",
      "Price-to-earnings ratio and price-to-book ratio together provide the most reliable quick screen for whether a stock is cheap or expensive relative to its intrinsic value",
      "A diversified portfolio of 10-30 stocks in different industries provides all the risk reduction that diversification can offer — beyond this, adding positions provides negligible additional benefit"
    ],
    mindmap: { title: "The Intelligent Investor", branches: [
      { name: "Core Philosophy", leaves: [
        { name: "Investment vs Speculation Defined", detail: "An investment operation is one which, upon thorough analysis, promises safety of principal and an adequate return — operations not meeting these requirements are speculative" },
        { name: "The Margin of Safety Principle", detail: "Pay substantially less than your conservative estimate of intrinsic value — this buffer absorbs errors in analysis, unfavorable business developments, and market mispricing" },
        { name: "Long-Term Orientation", detail: "The intelligent investor is not concerned with daily price fluctuations — they have invested based on a fundamental analysis of value and wait for that value to be recognized" },
        { name: "Independent Thinking", detail: "Following the crowd means buying what is popular and selling what is depressed — the investor who thinks independently and acts on thorough analysis systematically buys from the fearful and sells to the greedy" },
        { name: "Realistic Expectations", detail: "Graham believed the defensive investor should aim for adequate returns, not exceptional ones — trying to outperform the market significantly increases the risk of performing worse than it" }
      ]},
      { name: "Mr. Market", leaves: [
        { name: "The Parable Explained", detail: "Imagine owning shares in a business with a partner named Mr. Market, who every day offers to buy your shares or sell his at a price he names — sometimes his price is high, sometimes irrationally low" },
        { name: "Use Him, Do Not Follow Him", detail: "Mr. Market's offers are for your benefit, not your instruction — if his price is absurdly high, sell to him; if absurdly low, buy from him; otherwise, ignore him completely" },
        { name: "Market Price vs Intrinsic Value", detail: "In the short run, price can deviate significantly from value in either direction — the intelligent investor exploits this gap by buying value when price is far below it" },
        { name: "Volatility as Opportunity", detail: "The more volatile and irrational Mr. Market becomes, the more opportunities he creates for the prepared investor — volatility is the investor's friend, not their enemy" },
        { name: "Why Most Investors Fail", detail: "Most investors treat Mr. Market as a guide rather than a servant — they buy when he is enthusiastic (prices high) and sell when he is depressed (prices low), guaranteeing below-average results" }
      ]},
      { name: "Margin of Safety", leaves: [
        { name: "Quantifying the Margin", detail: "Graham typically sought stocks trading at two-thirds or less of their net current asset value (current assets minus all liabilities) — the deeper the discount, the larger the margin of safety" },
        { name: "Why It Works", detail: "A large margin of safety means you can be wrong about the business, wrong about timing, and still not lose money — the excess of value over price absorbs errors and misfortunes" },
        { name: "Margin of Safety in Bonds", detail: "For bonds, margin of safety is the excess of earnings power above the interest payment — Graham required earnings to cover interest charges by a multiple of at least 5x for industrials" },
        { name: "Intrinsic Value Estimation", detail: "Graham estimated intrinsic value using earnings power, asset value, and growth prospects, deliberately conservative — the goal is a range of reasonable value, not a precise number" },
        { name: "The Safety Net", detail: "By buying at a sufficient discount to intrinsic value, the investor is protected even if the business performs worse than expected — the price already reflects pessimism" }
      ]},
      { name: "Defensive Investor Strategy", leaves: [
        { name: "The 50-50 Starting Point", detail: "Begin with 50% in high-grade bonds and 50% in diversified stocks — adjust within the 25-75% range for each based on market valuations and personal circumstances, never going to extremes" },
        { name: "Stock Selection Criteria for Defensive Investor", detail: "Adequate size (avoid tiny companies), strong current ratio (2:1 minimum), no deficit in past 5 years, 20 years of consecutive dividends, 10 years of positive earnings, P/E below 15, price-to-book below 1.5" },
        { name: "Dollar-Cost Averaging", detail: "Invest fixed dollar amounts at regular intervals regardless of market price — this automatically buys more shares when prices are low and fewer when high, lowering the average cost per share over time" },
        { name: "Minimum Portfolio Diversification", detail: "Own at least 10 different companies in different industries to eliminate company-specific risk — but no more than 30, beyond which diversification provides diminishing benefit" },
        { name: "The Index Fund Alternative", detail: "Graham acknowledged in later editions that the defensive investor achieves a satisfactory result simply by buying low-cost index funds — this captures the market return without the effort of stock selection" },
        { name: "Rebalancing Discipline", detail: "When the stock portion grows to 75% due to market appreciation, sell stocks and buy bonds to return to balance — this enforces selling high and buying low automatically" }
      ]},
      { name: "Enterprising Investor Strategy", leaves: [
        { name: "Net-Net Stocks (Bargain Issues)", detail: "Buy stocks trading below net current asset value (current assets minus all liabilities) — Graham called these 'buying dollars for fifty cents'; this approach has the strongest theoretical and empirical support in the book" },
        { name: "Special Situations", detail: "Corporate events including mergers, spinoffs, recapitalizations, and bankruptcy reorganizations create pricing inefficiencies — the enterprising investor who does the analytical work can capture these inefficiencies" },
        { name: "Growth Stocks at Reasonable Prices", detail: "Graham recognized that superior growth companies deserve higher P/E ratios, but only up to a point — paying more than 15-16x earnings for any company introduces speculation, as the growth must materialize to justify the price" },
        { name: "Secondary Companies", detail: "Smaller, less-followed companies with solid fundamentals often trade at lower valuations than large-cap leaders — enterprising investors who research these companies can find greater margins of safety" },
        { name: "Turnaround Situations", detail: "Companies that have temporarily fallen out of favor due to business problems often trade far below their recovery value — the enterprising investor who correctly identifies recoveries can achieve exceptional returns" }
      ]},
      { name: "Stock Selection Criteria", leaves: [
        { name: "Earnings Stability", detail: "Require positive earnings in each of the past 10 years with no deficit year — this eliminates speculative growth companies that have never proven the ability to consistently generate profits" },
        { name: "Dividend Record", detail: "Require uninterrupted dividend payments for at least 20 years — this demonstrates financial discipline, consistent profitability, and commitment to returning capital to shareholders across multiple economic cycles" },
        { name: "Financial Strength Ratios", detail: "Current ratio of at least 2:1 for industrial companies; long-term debt should not exceed net current assets — these ratios ensure the company can survive a business downturn without financial distress" },
        { name: "Valuation Limits", detail: "Graham's classic formula: multiply P/E by price-to-book; the product should not exceed 22.5, equivalent to 15x earnings and 1.5x book value — this prevents overpaying for quality" },
        { name: "Earnings Growth Requirement", detail: "Require at least 33% cumulative growth in per-share earnings over 10 years (about 3% per year) — this modest hurdle eliminates secular decline companies while not requiring growth stock valuations" }
      ]},
      { name: "Market Fluctuations", leaves: [
        { name: "Bull Markets Breed Speculation", detail: "Extended bull markets gradually convert investors into speculators as rising prices seem to validate the purchase of any security — this sets the stage for the subsequent bear market to be devastating" },
        { name: "Bear Markets as Buying Opportunities", detail: "The investor who has cash and conviction during a bear market is in the strongest possible position — falling prices on quality companies increase the margin of safety and improve prospective returns" },
        { name: "Market Timing Is Impractical", detail: "Graham explicitly rejected market timing as a strategy — the cost of being wrong (missing the recovery) is too high, and no reliable method for predicting market direction has ever been proven" },
        { name: "The Inflation Threat", detail: "Graham believed the defensive investor should always hold some stocks as a hedge against inflation — bonds that appear safe can destroy real purchasing power over a decade of moderate inflation" },
        { name: "Valuation and Future Returns", detail: "The P/E ratio of the market is a rough predictor of long-term future returns — buying when valuations are low has consistently produced better 10-year returns than buying when valuations are high" }
      ]},
      { name: "Investment vs Speculation", leaves: [
        { name: "The Speculator's Mindset", detail: "The speculator's primary interest is in anticipating and profiting from market fluctuations — this is a legitimate activity but requires admitting you are speculating, not investing" },
        { name: "Why Speculation Is Negative-Sum", detail: "For every speculator who profits from a short-term price move, another speculator on the other side loses — before transaction costs, speculation is a zero-sum game; after costs, it is negative-sum" },
        { name: "When Growth Stocks Become Speculation", detail: "Paying excessive multiples for growth stocks converts an investment into a speculation — you are no longer relying on the company's fundamental value but on the continued enthusiasm of other market participants" },
        { name: "IPOs Are Generally Speculative", detail: "IPOs are sold in favorable market conditions for sellers, not buyers — the timing and pricing are controlled by insiders who know the business far better than the public investor" },
        { name: "Intelligent Speculation Is Acceptable", detail: "Graham did not condemn all speculation — he condemned unintelligent speculation and speculation that is mistaken for investment; a small speculative allocation with money you can afford to lose is acceptable" }
      ]},
      { name: "Common Investor Mistakes", leaves: [
        { name: "Paying Too Much for Growth", detail: "The biggest mistake of most investors is paying prices that require highly optimistic assumptions about the future to be justified — even a great company is a poor investment at a high enough price" },
        { name: "Following Analyst Recommendations", detail: "Wall Street analyst recommendations are structurally biased toward buy ratings — the incentives of the firms employing analysts are not aligned with the interests of the retail investor" },
        { name: "Overreacting to Market News", detail: "Daily financial news is designed to capture attention, not to provide investment guidance — responding to every piece of news converts a long-term investor into a short-term speculator" },
        { name: "Ignoring Business Quality for Price Alone", detail: "A cheap stock in a declining business is often not a bargain — the price can always fall further if the business continues to deteriorate; quality must be assessed alongside valuation" },
        { name: "Measuring Performance Against the Market", detail: "Checking your portfolio against the S&P 500 every quarter encourages impatient, benchmark-driven behavior — over short periods, intelligent value investing will frequently underperform a rising market" }
      ]},
      { name: "Building a Portfolio", leaves: [
        { name: "Start with the Asset Allocation Decision", detail: "The most important decision is the split between stocks and bonds — this determines the vast majority of portfolio volatility and long-term return; individual stock selection matters less than this foundational choice" },
        { name: "Diversify Across Industries", detail: "Do not concentrate in one sector even if the valuations are compelling — correlation within sectors means all positions are likely to move together in a sector-specific downturn" },
        { name: "The Role of Bonds", detail: "Bonds provide stability, income, and dry powder for stock purchases during market declines — they are not optional even when stocks appear more attractive; they reduce the temptation to sell stocks in a downturn" },
        { name: "Annual Review, Not Daily Monitoring", detail: "The intelligent investor reviews their portfolio annually to check whether the businesses owned remain sound and whether valuations have become extreme — daily monitoring encourages emotional reactions" },
        { name: "Transaction Costs and Taxes", detail: "Every unnecessary transaction generates a commission and potentially a taxable gain — the buy-and-hold approach Graham advocates is not just philosophically sound but financially superior due to minimized friction costs" }
      ]}
    ]}
  },
  common_stocks_and_uncommon_profits: {
    summary: "Philip Fisher pioneered growth investing and the scuttlebutt method of researching companies. His 15-point checklist for evaluating growth stocks focuses on management quality, research and development, sales organization, and profit margins. Fisher believed in concentrating in a few outstanding companies and holding them for very long periods — the opposite of diversified value investing.",
    keyTakeaways: ["The scuttlebutt method — talking to customers, suppliers, and competitors — reveals more than financial statements alone", "Great companies are defined by their management, not just their numbers", "Buy and hold outstanding companies for decades — the best returns come from sitting tight", "The 15-point checklist systematically evaluates whether a company can sustain above-average growth", "There are only three reasons to sell: you made a mistake, the company fundamentals deteriorated, or you found something dramatically better"],
    mindmap: { title: "Common Stocks and Uncommon Profits", branches: [
      { name: "Scuttlebutt Method", leaves: [{ name: "Talk to Customers", detail: "Are they loyal? Would they switch? What do they think of the product?" }, { name: "Talk to Competitors", detail: "Competitors know each other's strengths and weaknesses intimately" }, { name: "Talk to Suppliers", detail: "Suppliers see order trends and management quality firsthand" }] },
      { name: "15-Point Checklist (Key Points)", leaves: [{ name: "Growth Potential", detail: "Does the company have products to sustain above-average growth for years?" }, { name: "R&D Effectiveness", detail: "Is management committed to developing new products and processes?" }, { name: "Profit Margins", detail: "Are margins maintained or improving as the company grows?" }, { name: "Management Integrity", detail: "Does management communicate honestly with investors, especially about problems?" }] },
      { name: "When to Buy", leaves: [{ name: "Temporary Bad News", detail: "The best time to buy is when a great company faces a short-term problem" }, { name: "After Research", detail: "Never buy until you have thoroughly investigated using the 15 points" }, { name: "Concentrate", detail: "Own a few outstanding companies rather than many mediocre ones" }] },
      { name: "When to Sell", leaves: [{ name: "You Were Wrong", detail: "Your original assessment of the company was incorrect" }, { name: "Fundamentals Changed", detail: "The company no longer meets the 15-point criteria" }, { name: "Almost Never for Valuation", detail: "Do not sell a great company just because it seems fully valued" }] }
    ]}
  },
  market_wizards: {
    summary: "Jack Schwager interviews the greatest traders of the 1980s, revealing their diverse strategies, philosophies, and mindsets. From trend followers to contrarians, discretionary traders to systematic ones, the book shows there is no single path to trading success. The common threads across all interviews: discipline, risk management, and a deep personal commitment to their craft.",
    keyTakeaways: ["There are many different ways to succeed in markets — find the approach that fits your personality", "Every great trader has strict risk management — none of them risk more than a small percentage per trade", "Losses are inevitable and necessary — the key is keeping them small and learning from them", "Most successful traders went through a period of struggle and failure before finding their edge", "Discipline and emotional control separate the winners from the losers more than strategy or intelligence"],
    mindmap: { title: "Market Wizards", branches: [
      { name: "Common Principles", leaves: [{ name: "Risk Management First", detail: "Every wizard emphasizes protecting capital above all else" }, { name: "Discipline", detail: "Following your rules consistently, especially during drawdowns" }, { name: "Passion for Markets", detail: "Every wizard is deeply passionate about trading — it is not just about money" }] },
      { name: "Diverse Approaches", leaves: [{ name: "Trend Following", detail: "Ed Seykota, Richard Dennis — ride major trends, cut losers fast" }, { name: "Fundamental Analysis", detail: "Jim Rogers — understand macro economics and global trends" }, { name: "Contrarian", detail: "Paul Tudor Jones — fade the crowd at extremes" }] },
      { name: "Psychology", leaves: [{ name: "Learn from Losses", detail: "Every wizard views losses as tuition — the cost of market education" }, { name: "Confidence Without Ego", detail: "Strong belief in their approach but humble enough to admit when wrong" }, { name: "Emotional Detachment", detail: "Separate self-worth from trading P&L" }] },
      { name: "Practical Wisdom", leaves: [{ name: "Start Small", detail: "Every wizard started with small amounts and scaled up gradually" }, { name: "Keep It Simple", detail: "Most winning strategies are surprisingly simple at their core" }, { name: "Know When to Sit Out", detail: "The best traders know when conditions are not favorable and stay flat" }] }
    ]}
  },
  you_can_be_a_stock_market_genius: {
    summary: "Joel Greenblatt reveals the hidden corners of the market where individual investors can find extraordinary opportunities. Spinoffs, restructurings, mergers, bankruptcy emergences, and other special situations create pricing inefficiencies that most investors overlook. Because these situations are complex and institutional investors are structurally unable to participate, they offer genuine alpha for those willing to do the work.",
    keyTakeaways: ["Special situations create inefficiencies because institutional investors are forced sellers or unable to participate", "Spinoffs outperform the market because parent company shareholders dump the spinoff shares without analysis", "Risk arbitrage (merger arbitrage) offers consistent but modest returns with careful position sizing", "LEAPS (long-term options) on deeply undervalued stocks provide leveraged exposure with defined risk", "The best opportunities are in situations too small, too complex, or too boring for Wall Street to cover"],
    mindmap: { title: "Stock Market Genius", branches: [
      { name: "Spinoffs", leaves: [{ name: "Forced Selling", detail: "Index funds and institutions dump spinoff shares creating artificial selling pressure" }, { name: "Hidden Value", detail: "The spun-off entity is often a better business freed from the parent's shadow" }, { name: "Insider Buying", detail: "Watch for management of the new entity buying shares aggressively" }] },
      { name: "Restructurings", leaves: [{ name: "Bankruptcy Emergence", detail: "Companies emerging from Chapter 11 are often deeply undervalued" }, { name: "Recapitalizations", detail: "Leveraged recaps can unlock significant shareholder value" }, { name: "Asset Sales", detail: "Companies selling divisions may be worth more as parts than as a whole" }] },
      { name: "Merger Arbitrage", leaves: [{ name: "Spread Capture", detail: "Buy target stock at a discount to the acquisition price" }, { name: "Deal Risk", detail: "Analyze regulatory, financing, and shareholder approval risks" }, { name: "Position Sizing", detail: "Small positions across many deals reduces impact of any single deal failure" }] },
      { name: "Why It Works", leaves: [{ name: "Structural Inefficiency", detail: "Wall Street ignores situations that do not fit into standard categories" }, { name: "Complexity Premium", detail: "Complex situations require work that most investors will not do" }, { name: "Small Size", detail: "Deals too small for institutions are perfectly sized for individuals" }] }
    ]}
  },
  margin_of_safety: {
    summary: "Seth Klarman's legendary, out-of-print book expands on Benjamin Graham's value investing principles for the modern era. Klarman emphasizes the paramount importance of risk avoidance over return maximization, argues that most investors are their own worst enemies, and provides a framework for finding deeply discounted investments in complex and distressed situations. The book's scarcity (copies sell for hundreds of dollars) has made it almost mythical in investing circles.",
    keyTakeaways: ["Risk avoidance should be the primary goal — returns follow naturally when you avoid permanent capital loss", "Most institutional investors are structured to fail — benchmark tracking, quarterly performance pressure, and career risk all lead to poor decisions", "Value investing works because most market participants have short time horizons and emotional reactions", "Distressed debt, liquidations, and complex corporate events offer the deepest value opportunities", "Patience is the most underrated investment skill — the best opportunities come to those who wait"],
    mindmap: { title: "Margin of Safety", branches: [
      { name: "Risk-Averse Philosophy", leaves: [{ name: "Avoid Permanent Loss", detail: "The first rule of investing is do not lose money — the second rule is do not forget rule one" }, { name: "Margin of Safety", detail: "Buy at a significant discount to conservative estimate of intrinsic value" }, { name: "Worst-Case Thinking", detail: "Evaluate investments based on what could go wrong, not what could go right" }] },
      { name: "Why Institutions Fail", leaves: [{ name: "Benchmark Obsession", detail: "Tracking error minimization prevents genuine value investing" }, { name: "Career Risk", detail: "Being wrong conventionally is safer than being right unconventionally" }, { name: "Short-Term Pressure", detail: "Quarterly performance evaluation forces short-term thinking" }] },
      { name: "Finding Value", leaves: [{ name: "Distressed Debt", detail: "Bonds of troubled companies trade at deep discounts with potential for full recovery" }, { name: "Liquidations", detail: "Companies worth more dead than alive offer guaranteed returns at the right price" }, { name: "Complex Situations", detail: "Spinoffs, recaps, and restructurings create pricing inefficiencies" }] },
      { name: "Investor Discipline", leaves: [{ name: "Patience", detail: "Wait for fat pitches — you do not have to swing at every opportunity" }, { name: "Independent Thinking", detail: "Value investing requires going against the crowd when the crowd is wrong" }, { name: "Process Over Outcome", detail: "Good investment decisions can have bad outcomes — judge the process, not the result" }] }
    ]}
  }
};
